<script setup lang="ts">import{computed,onMounted,ref}from"vue";import{useRoute,useRouter}from"vue-router";import{ChevronDown,ShieldCheck}from"lucide-vue-next";import{api,type Doctor,type Person,type Schedule}from"../api";import PageHeader from"../components/PageHeader.vue";const route=useRoute(),router=useRouter(),doctor=ref<Doctor>(),schedule=ref<Schedule>(),people=ref<Person[]>([]),personId=ref<number>(),name=ref(""),phone=ref(""),idCard=ref(""),rulesOpen=ref(false),agree=ref(false),message=ref("");const valid=computed(()=>name.value.trim().length>=2&&/^1[3-9]\d{9}$/.test(phone.value)&&/^(\d{15}|\d{17}[0-9Xx])$/.test(idCard.value)&&agree.value);onMounted(async()=>{const did=Number(route.params.doctorId),sid=Number(route.params.scheduleId);[doctor.value,people.value]=await Promise.all([api.doctor(did),api.people()]);schedule.value=(await api.schedules(did)).find(x=>x.id===sid);const p=people.value.find(x=>x.isDefault)||people.value[0];if(p){personId.value=p.id;name.value=p.name;phone.value=p.phone}});async function submit(){if(!valid.value||!doctor.value||!schedule.value)return;try{let pid=personId.value;if(!pid){const p=await api.addPerson({name:name.value,phone:phone.value,idCard:idCard.value.toUpperCase(),relationship:"self",isDefault:true});pid=p.id}const o=await api.register({registrationPersonId:pid,hospitalId:doctor.value.hospitalId,departmentId:doctor.value.departmentId,doctorId:doctor.value.id,scheduleId:schedule.value.id});router.replace(`/orders/${o.id}`)}catch(e){message.value=e instanceof Error?e.message:"预约失败"}}</script><template><main v-if="doctor&&schedule"><PageHeader title="确认预约"/><section class="booking-doctor"><div class="avatar">{{doctor.name[0]}}</div><div><h2>{{doctor.name}} <small>{{doctor.title}} · {{doctor.departmentName}}</small></h2><p>{{doctor.hospitalName}}</p></div></section><section class="booking-card"><h3>号源信息</h3><dl><dt>日期</dt><dd>{{schedule.scheduleDate}}　{{schedule.period}}</dd><dt>医院</dt><dd>{{doctor.hospitalName}}</dd><dt>地点</dt><dd>{{schedule.hospitalName}}</dd><dt>费用</dt><dd class="price">¥{{schedule.fee}}（到院支付）</dd></dl><small>挂号费由医院自行设定，平台不收取额外费用</small></section><section class="booking-card patient-form"><h3>预约信息</h3><label>姓名<input v-model="name" placeholder="请输入就诊人姓名"/></label><label>手机号<input :value="phone" @input="phone=($event.target as HTMLInputElement).value.replace(/\D/g,'').slice(0,11)" inputmode="numeric"/></label><label>身份证号<input :value="idCard" @input="idCard=($event.target as HTMLInputElement).value.replace(/[^0-9Xx]/g,'').slice(0,18)" placeholder="15位或18位身份证号"/></label><p v-if="idCard&&!/^(\d{15}|\d{17}[0-9Xx])$/.test(idCard)" class="form-message">身份证号格式不正确</p></section><section class="booking-card rules"><button @click="rulesOpen=!rulesOpen"><b>预约规则</b><ChevronDown :class="{rotate:rulesOpen}"/></button><div :class="{clamped:!rulesOpen}"><p>* 专家门诊资源有限，如预约成功后不能按时就诊，请尽早取消。</p><p>* 网上挂号实行实名制，请填写真实姓名、手机号和身份证号。</p><p>* 就诊时请携带身份证、医保卡，并提前到院取号。</p></div></section><label class="agree"><input type="checkbox" v-model="agree"/>我已阅读并同意预约规则</label><p v-if="message" class="form-message center">{{message}}</p><button class="booking-submit" :disabled="!valid" @click="submit"><ShieldCheck/>立即挂号</button></main>
</template>
